function largestPathValue(colors, edges) {
    function dfs(node) {
        if (!cache[node][colors.charCodeAt(node) - 'a'.charCodeAt(0)]) {
            cache[node][colors.charCodeAt(node) - 'a'.charCodeAt(0)] = 1;
            for (const neighbor of graph[node]) {
                cache[node][colors.charCodeAt(node) - 'a'.charCodeAt(0)] = Math.max(cache[node][colors.charCodeAt(node) - 'a'.charCodeAt(0)], 1 + dfs(neighbor));
            }
        }
        return cache[node][colors.charCodeAt(node) - 'a'.charCodeAt(0)];
    }

    const n = colors.length;
    const graph = new Array(n).fill().map(() => new Set());
    for (const edge of edges) {
        graph[edge[0]].add(edge[1]);
    }

    const cache = new Array(n).fill().map(() => new Array(26).fill(0));
    const inDegree = new Array(n).fill(0);
    for (const edge of edges) {
        inDegree[edge[1]]++;
    }
    let res = -1;
    for (let i = 0; i < n; i++) {
        if (inDegree[i] === 0) {
            res = Math.max(res, dfs(i));
        }
    }
    return res;
}
