import java.util.*;

class Solution {
    public int largestPathValue(String colors, int[][] edges) {
        int n = colors.length();
        List<Set<Integer>> graph = new ArrayList<>();
        for (int i = 0; i < n; i++) {
            graph.add(new HashSet<>());
        }
        for (int[] edge : edges) {
            graph.get(edge[0]).add(edge[1]);
        }
        int[][] cache = new int[n][26];
        int[] inDegree = new int[n];
        for (int[] edge : edges) {
            inDegree[edge[1]]++;
        }
        int res = -1;
        for (int i = 0; i < n; i++) {
            if (inDegree[i] == 0) {
                res = Math.max(res, dfs(i, graph, colors, cache));
            }
        }
        return res;
    }

    private int dfs(int node, List<Set<Integer>> graph, String colors, int[][] cache) {
        if (cache[node][colors.charAt(node) - 'a'] == 0) {
            cache[node][colors.charAt(node) - 'a'] = 1;
            for (int neighbor : graph.get(node)) {
                cache[node][colors.charAt(node) - 'a'] = Math.max(cache[node][colors.charAt(node) - 'a'], 1 + dfs(neighbor, graph, colors, cache));
            }
        }
        return cache[node][colors.charAt(node) - 'a'];
    }
}
